@page "/dispatcher"
@attribute [Authorize(Roles = "Dispatcher")]
@rendermode InteractiveAuto
@inject HttpClient Http

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <input class="form-control" placeholder="Search tracking #, destination, or email..."
               @bind="searchTerm" @bind:event="oninput" @onkeyup="HandleSearch" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter" @bind:after="LoadShipments">
            <option value="">All Statuses</option>
            @foreach (var s in statuses)
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-primary" @onclick="() => showCreateForm = !showCreateForm">
            @(showCreateForm ? "Cancel" : "＋ New Shipment")
        </button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Description" @bind="newShipment.Description" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="estimatedDeliveryDate" />
                </div>
                <div class="col-md-3 d-flex align-items-end">
                    <button class="btn btn-success" @onclick="CreateShipment" disabled="@isCreating">
                        @(isCreating ? "Creating..." : "Create")
                    </button>
                </div>
            </div>
            @if (!string.IsNullOrEmpty(createError))
            {
                <div class="alert alert-danger mt-2">@createError</div>
            }
        </div>
    </div>
}

@if (shipments == null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Length == 0)
{
    <div class="alert alert-info">No shipments found.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Customer</th>
                    <th>Description</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in shipments)
                {
                    <tr>
                        <td><strong>@shipment.TrackingNumber</strong></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>@shipment.CustomerEmail</td>
                        <td>@shipment.Description</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">
                                @shipment.Status
                            </span>
                        </td>
                        <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    value="@shipment.Status"
                                    @onchange="(e) => UpdateStatus(shipment, e.Value?.ToString()!)">
                                @foreach (var s in statuses)
                                {
                                    <option value="@s" selected="@(s == shipment.Status)">@s</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (!string.IsNullOrEmpty(updateMessage))
{
    <div class="alert alert-success alert-dismissible mt-3">
        @updateMessage
        <button type="button" class="btn-close" @onclick="() => updateMessage = null"></button>
    </div>
}

@code {
    private ShipmentDto[]? shipments;
    private string searchTerm = "";
    private string statusFilter = "";
    private string? updateMessage;
    private bool showCreateForm;
    private bool isCreating;
    private string? createError;
    private ShipmentDto newShipment = new();
    private DateTime? estimatedDeliveryDate;

    private static readonly string[] statuses =
        ["Pending", "Picked Up", "In Transit", "Out for Delivery", "Delivered", "Cancelled"];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        var url = "/api/shipments?";
        if (!string.IsNullOrWhiteSpace(statusFilter))
            url += $"status={Uri.EscapeDataString(statusFilter)}&";
        if (!string.IsNullOrWhiteSpace(searchTerm))
            url += $"search={Uri.EscapeDataString(searchTerm)}&";

        shipments = await Http.GetFromJsonAsync<ShipmentDto[]>(url.TrimEnd('&', '?'));
    }

    private async Task HandleSearch()
    {
        await LoadShipments();
    }

    private async Task UpdateStatus(ShipmentDto shipment, string newStatus)
    {
        if (newStatus == shipment.Status) return;

        var response = await Http.PutAsJsonAsync(
            $"/api/shipments/{shipment.Id}/status",
            new { Status = newStatus });

        if (response.IsSuccessStatusCode)
        {
            shipment.Status = newStatus;
            updateMessage = $"Shipment {shipment.TrackingNumber} updated to '{newStatus}'.";
        }
    }

    private async Task CreateShipment()
    {
        createError = null;
        isCreating = true;

        if (estimatedDeliveryDate.HasValue)
            newShipment.EstimatedDelivery = estimatedDeliveryDate.Value;

        var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            showCreateForm = false;
            newShipment = new();
            estimatedDeliveryDate = null;
            await LoadShipments();
        }
        else
        {
            createError = "Failed to create shipment. Please check all fields.";
        }

        isCreating = false;
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "Picked Up" => "bg-info text-dark",
        "In Transit" => "bg-primary",
        "Out for Delivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@rendermode InteractiveAuto

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>
<p>Enter your tracking number to check the current status and estimated delivery.</p>

<div class="row mb-4">
    <div class="col-md-5">
        <div class="input-group">
            <input class="form-control form-control-lg" placeholder="e.g. TRK-20260501-001"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary btn-lg" @onclick="TrackShipment" disabled="@isSearching">
                @(isSearching ? "Searching..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (hasSearched && result == null && !isSearching)
{
    <div class="alert alert-warning">
        <strong>Shipment not found.</strong> Please check your tracking number and try again.
    </div>
}

@if (result != null)
{
    <div class="card shadow-sm">
        <div class="card-header bg-primary text-white">
            <h4 class="mb-0">Shipment @result.TrackingNumber</h4>
        </div>
        <div class="card-body">
            <div class="row mb-3">
                <div class="col-md-12">
                    <div class="d-flex justify-content-between align-items-center mb-3">
                        @foreach (var step in statusSteps)
                        {
                            var isActive = GetStepIndex(result.Status) >= GetStepIndex(step);
                            var isCurrent = result.Status == step;
                            <div class="text-center flex-fill">
                                <div class="rounded-circle mx-auto d-flex align-items-center justify-content-center @(isActive ? "bg-success" : "bg-light border")"
                                     style="width: 40px; height: 40px;">
                                    @if (isActive)
                                    {
                                        <span class="text-white">✓</span>
                                    }
                                </div>
                                <small class="@(isCurrent ? "fw-bold" : "text-muted")">@step</small>
                            </div>
                        }
                    </div>
                </div>
            </div>

            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(result.Status) fs-6">@result.Status</span></dd>

                        <dt>Description</dt>
                        <dd>@result.Description</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>From</dt>
                        <dd>@result.Origin</dd>

                        <dt>To</dt>
                        <dd>@result.Destination</dd>

                        <dt>Shipped On</dt>
                        <dd>@result.CreatedAt.ToString("MMMM dd, yyyy")</dd>

                        @if (result.Status == "Delivered" && result.DeliveredAt.HasValue)
                        {
                            <dt>Delivered On</dt>
                            <dd class="text-success fw-bold">@result.DeliveredAt.Value.ToString("MMMM dd, yyyy 'at' h:mm tt")</dd>
                        }
                        else if (result.EstimatedDelivery.HasValue)
                        {
                            <dt>Estimated Delivery</dt>
                            <dd class="fw-bold">@result.EstimatedDelivery.Value.ToString("MMMM dd, yyyy")</dd>
                        }
                    </dl>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private TrackingResult? result;
    private bool isSearching;
    private bool hasSearched;

    [Inject] private HttpClient Http { get; set; } = default!;

    private static readonly string[] statusSteps =
        ["Pending", "Picked Up", "In Transit", "Out for Delivery", "Delivered"];

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isSearching = true;
        hasSearched = true;
        result = null;

        try
        {
            var response = await Http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
            if (response.IsSuccessStatusCode)
            {
                result = await response.Content.ReadFromJsonAsync<TrackingResult>();
            }
        }
        catch
        {
            // Network error — result stays null, showing "not found" message
        }
        finally
        {
            isSearching = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private static int GetStepIndex(string status) => status switch
    {
        "Pending" => 0,
        "Picked Up" => 1,
        "In Transit" => 2,
        "Out for Delivery" => 3,
        "Delivered" => 4,
        _ => -1
    };

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "Picked Up" => "bg-info text-dark",
        "In Transit" => "bg-primary",
        "Out for Delivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };
}

